-- ESTUDIAR · Fase E-2 (PORTUGUÉS) — A1+A2 (unidades 1-12), SOLO DATOS.
-- La tabla study_theory y las RPCs get_study_theory/submit_study_quiz ya viven
-- desde la mig 178 y son course-agnósticas POR CONSTRUCCIÓN: derivan el curso de
-- la propia unidad (v_unit.course_id), no de un idioma fijo. Aquí
-- solo se insertan los 12 temas de pt (upsert idempotente por (course_id,
-- unit_order) → el INGLÉS queda intacto, es otro course_id).
-- NO toca motor FSRS, economía, gating, certificación ni los otros 5 idiomas.
-- El quiz sigue siendo FORMATIVO (jz_grade, sin XP/oro).


-- ── Datos (idempotente por (course_id, unit_order)) ────────────────────────
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 13, 'B1', 'Cuando era niño', 'Aprende el pretérito imperfeito para hablar de hábitos y descripciones del pasado, y a distinguirlo del pretérito perfeito, que cuenta hechos puntuales.', '[{"heading": "Formar el imperfeito: la V manda", "body": "En pt-BR los verbos en -ar hacen -ava (brincar → brincava) y los de -er/-ir hacen -ia (comer → comia, dormir → dormia). Ojo: donde el español escribe B, el portugués escribe V.", "bullets": ["-ar: eu brincava, você brincava, nós brincávamos, eles brincavam.", "-er/-ir: eu comia, ele dormia, nós comíamos, eles comiam.", "Cuatro irregulares (+ ir → ia): ser, ter, ir, vir, pôr.", "«A gente» pide 3ª persona singular: a gente brincava."]}, {"heading": "Los cinco irregulares", "body": "El imperfeito casi no tiene sorpresas: ser → era, ter → tinha, ir → ia, vir → vinha, pôr → punha. Los demás verbos siguen el patrón regular, incluso los que son irregulares en presente.", "bullets": ["ser: eu era, nós éramos, eles eram.", "ter: eu tinha, nós tínhamos, eles tinham.", "ir: eu ia; vir: eu vinha; pôr: eu punha.", "Fazer y poder son regulares aquí: fazia, podia."]}, {"heading": "Imperfeito o perfeito: hábito frente a hecho", "body": "El imperfeito describe cómo eran las cosas y qué pasaba siempre; el perfeito cuenta un hecho terminado y puntual. Con «costumava» + infinitivo dices lo mismo que con el imperfeito de hábito.", "bullets": ["Hábito: todo domingo nós íamos à praia.", "Hecho puntual: ontem nós fomos à praia.", "Descripción: a casa era grande e tinha um quintal.", "«Eu costumava brincar» = «eu brincava» (hábito)."]}]'::jsonb, '[{"pt": "Quando eu era criança, brincava na rua com meus primos.", "es": "Cuando era niño, jugaba en la calle con mis primos.", "text": "Quando eu era criança, brincava na rua com meus primos.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/45e1aebd-ded5-579c-b5c4-8c26a3450e31.mp3"}, {"pt": "A gente sempre comia na casa da minha avó no domingo.", "es": "Nosotros siempre comíamos en casa de mi abuela el domingo.", "text": "A gente sempre comia na casa da minha avó no domingo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/41bcdbcb-f1ff-5eef-97a6-0f1f0f57a9ed.mp3"}, {"pt": "Eu costumava dormir cedo, mas ontem dormi às duas da manhã.", "es": "Yo solía dormir temprano, pero ayer me dormí a las dos de la mañana.", "text": "Eu costumava dormir cedo, mas ontem dormi às duas da manhã.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e311cb13-8b0c-5ba0-9a5a-5aac1ee539f6.mp3"}, {"pt": "A escola era pequena e nós tínhamos aula só de manhã.", "es": "La escuela era pequeña y teníamos clase solo por la mañana.", "text": "A escola era pequena e nós tínhamos aula só de manhã.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7e45ce50-fcf0-53da-94ef-23ad08820994.mp3"}]'::jsonb, '[{"title": "«brincaba» no existe: es brincava", "body": "El español escribe -aba (jugaba, hablaba) y el portugués escribe -ava: brincava, falava, morava, trabalhava. Es la misma terminación con V, y se pronuncia con V. Nunca escribas -aba en portugués."}, {"title": "«A gente» no lleva verbo de nosotros", "body": "«A gente» significa nosotros, pero el verbo va en 3ª persona del singular: a gente brincava, a gente tinha, a gente ia. Decir «a gente brincávamos» es un error frecuente del hispanohablante."}, {"title": "Un hecho puntual no va en imperfeito", "body": "«Ontem eu ia ao cinema» no cuenta que fuiste: para un hecho terminado usa o perfeito, «ontem eu fui ao cinema». El imperfeito queda para lo repetido o lo que describe el escenario."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta del imperfeito: «Quando eu era criança, eu ___ na rua.»", "options": ["brincava", "brincaba", "brinquei"], "answer": "brincava", "id": "u13q1"}, {"type": "multiple_choice", "prompt": "«A gente» va con verbo en 3ª persona del singular. ¿Cuál frase es correcta?", "options": ["A gente tinha um cachorro", "A gente tínhamos um cachorro", "A gente tiveram um cachorro"], "answer": "A gente tinha um cachorro", "id": "u13q2"}, {"type": "multiple_choice", "prompt": "Un hecho puntual y terminado. ¿Cuál frase es correcta para «ayer fui al cine»?", "options": ["Ontem eu fui ao cinema", "Ontem eu ia ao cinema", "Ontem eu vou ao cinema"], "answer": "Ontem eu fui ao cinema", "id": "u13q3"}, {"type": "cloze", "prompt": "Completa con el imperfeito del verbo «morar» en la 1ª persona del plural (nós).", "text": "Antigamente nós ___ no interior.", "answer": "morávamos", "accepted": ["morávamos", "costumávamos morar"], "id": "u13q4"}, {"type": "cloze", "prompt": "Completa con UNA palabra: el imperfeito del verbo «ser» en la 3ª persona del singular.", "text": "A minha escola ___ pequena e bonita.", "answer": "era", "accepted": ["era"], "id": "u13q5"}]'::jsonb)
