  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 17, 'B1', 'Problemas y soluciones', 'Cómo contar que algo falló y cómo ofrecer la solución en portugués brasileño real: «quebrou», «deu problema», «tem jeito?», «dá para…?» y el comodín «dar» (deu certo / deu errado / não deu).', '[{"heading": "Cuando algo falla: «quebrou» y «deu problema»", "body": "En Brasil, un aparato que deja de funcionar «quebra», no «se rompe». Para un fallo puntual (el sistema, el coche, un plan) se dice «deu problema». También oirás «não funciona» y «está com defeito».", "bullets": ["«Meu carro quebrou» = mi coche se averió.", "«Deu problema no sistema» = el sistema falló.", "«Está com defeito» = tiene un defecto, está fallando."]}, {"heading": "Buscar solución: «tem jeito?», «dá para…?», «vou resolver»", "body": "«Tem jeito?» pregunta si hay alguna manera de arreglarlo. «Dá para + infinitivo?» equivale a «¿se puede…?» y es impersonal: no cambia de persona. Para prometer la solución: «vou resolver» o «eu resolvo».", "bullets": ["«Tem jeito de trocar?» = ¿hay manera de cambiarlo?", "«Dá para entregar hoje?» = ¿se puede entregar hoy?", "«Deixa comigo, vou resolver» tranquiliza al interlocutor."]}, {"heading": "«Dar» como comodín: deu certo, deu errado, não deu", "body": "El verbo «dar» resuelve mil situaciones. «Deu certo» = salió bien; «deu errado» = salió mal; «não deu» = no pudo ser. Hablan del resultado y aparecen casi siempre en pasado con «deu».", "bullets": ["«Deu tudo certo!» = ¡salió todo bien!", "«Não deu para ir» = no pude ir.", "«Deu errado» habla del resultado, no del objeto."]}]'::jsonb, '[{"pt": "Meu celular quebrou ontem.", "es": "Se me rompió el móvil ayer.", "text": "Meu celular quebrou ontem.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/2e887b6e-60bc-5ebb-9542-159d52c73907.mp3"}, {"pt": "Deu problema no sistema, mas eu vou resolver hoje.", "es": "Falló el sistema, pero yo lo voy a resolver hoy.", "text": "Deu problema no sistema, mas eu vou resolver hoje.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ef0ac11d-9d98-5300-965a-74329624b038.mp3"}, {"pt": "Tem jeito de trocar a passagem? Dá para fazer isso agora?", "es": "¿Hay manera de cambiar el billete? ¿Se puede hacer eso ahora?", "text": "Tem jeito de trocar a passagem? Dá para fazer isso agora?", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d5725003-ecc4-5d10-ab91-0467d5c8e669.mp3"}, {"pt": "Tentei consertar sozinho, mas não deu certo.", "es": "Intenté arreglarlo yo solo, pero no salió bien.", "text": "Tentei consertar sozinho, mas não deu certo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/fb6b9d6c-1a06-5b35-97b1-7c22f43d88df.mp3"}]'::jsonb, '[{"title": "«Se rompió» no se dice «se rompeu»", "body": "Cuando un aparato deja de funcionar, el brasileño dice «quebrou»: «o notebook quebrou». «Romper» existe, pero es formal y va con relaciones o contratos («romper com alguém»); para papel o tela se dice «rasgar»."}, {"title": "«Dá para…?» es impersonal: no lo conjugues", "body": "«Dá para» se queda siempre en tercera persona: «dá para você me ajudar?», nunca «dou para» ni «dás para». Decir «pode-se pagar aqui?» es correcto, pero suena formal; en el día a día se pregunta «dá para pagar aqui?»."}, {"title": "«Deu certo» no es lo mismo que «está certo»", "body": "«Deu certo» significa que algo salió bien, que funcionó (resultado). «Está certo» significa que algo es correcto. Compara: «a resposta está certa» (es correcta) frente a «o plano deu certo» (funcionó)."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Tu ordenador dejó de funcionar. ¿Cómo lo cuentas en Brasil?", "options": ["Meu computador quebrou.", "Meu computador se rompeu.", "Meu computador rasgou."], "answer": "Meu computador quebrou.", "id": "u17q1"}, {"type": "multiple_choice", "prompt": "Quieres preguntar «¿se puede pagar con tarjeta?» de forma coloquial. Elige la opción natural.", "options": ["Dá para pagar com cartão?", "Dou para pagar com cartão?", "Dá de pagar com cartão?"], "answer": "Dá para pagar com cartão?", "id": "u17q2"}, {"type": "multiple_choice", "prompt": "La reunión salió bien. ¿Cómo lo dices en portugués coloquial?", "options": ["A reunião deu certo.", "A reunião deu errado.", "A reunião está certa."], "answer": "A reunião deu certo.", "id": "u17q3"}, {"type": "cloze", "prompt": "Completa: el ascensor se averió ayer.", "text": "O elevador ___ ontem e ninguém consegue subir.", "answer": "quebrou", "accepted": ["quebrou", "deu problema", "parou"], "id": "u17q4"}, {"type": "cloze", "prompt": "Completa con el verbo comodín: «no salió bien».", "text": "Tentei três vezes, mas não ___ certo.", "answer": "deu", "accepted": ["deu"], "id": "u17q5"}]'::jsonb)
