insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 18, 'B1', 'Comparar y contar', 'Aprende a comparar en portugués: «mais/menos … (do) que», la igualdad con «tão … quanto», los irregulares melhor/pior/maior/menor y los superlativos («o melhor de todos», «caríssimo»).', '[{"heading": "Más, menos e igual", "body": "Para la superioridad y la inferioridad usa «mais/menos + adjetivo + (do) que». El «do» es opcional: ambas formas son correctas y muy usadas. Para la igualdad, en pt-BR lo más frecuente es «tão + adjetivo + quanto»; «tão… como» también se oye y es correcto.", "bullets": ["Este livro é mais caro (do) que aquele.", "Meu quarto é menos claro do que o seu.", "Ela é tão alta quanto o irmão.", "«Tão… como» también vale, pero se usa menos."]}, {"heading": "Los cuatro irregulares", "body": "Cuatro adjetivos tienen forma comparativa propia y no admiten «mais» delante: bom→melhor, ruim→pior, grande→maior, pequeno→menor. Son iguales en masculino y femenino, y su plural es melhores, piores, maiores, menores.", "bullets": ["bom → melhor; ruim → pior", "grande → maior; pequeno → menor", "Nunca «mais bom» ni «mais grande».", "Los adverbios: bem→melhor, mal→pior."]}, {"heading": "Superlativos: relativo y absoluto", "body": "El superlativo relativo compara dentro de un grupo: artículo + comparativo + «de» (nunca «em»): «a maior cidade do país». El absoluto expresa un grado altísimo con «muito» o con el sufijo -íssimo: «caro→caríssimo», «fácil→facílimo (o facilíssimo, más coloquial)», «bom→ótimo».", "bullets": ["É o melhor restaurante da cidade.", "Con grupo se usa «de»: do país, da turma.", "caro → caríssimo; difícil → dificílimo", "bom → ótimo; ruim → péssimo"]}]'::jsonb, '[{"pt": "São Paulo é maior do que o Rio de Janeiro.", "es": "São Paulo es más grande que Río de Janeiro.", "text": "São Paulo é maior do que o Rio de Janeiro.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9652e7ed-9449-5ed8-8188-9679c19b043c.mp3"}, {"pt": "Meu celular é tão rápido quanto o seu.", "es": "Mi celular es tan rápido como el tuyo.", "text": "Meu celular é tão rápido quanto o seu.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/505cc3cb-a8b1-5c38-83f8-f94a8e7b222e.mp3"}, {"pt": "Este é o melhor café da cidade.", "es": "Este es el mejor café de la ciudad.", "text": "Este é o melhor café da cidade.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9dae6e5c-ddcc-595a-91e6-93dbba8d2cfe.mp3"}, {"pt": "O aluguel aqui é caríssimo, mas o bairro é ótimo.", "es": "El alquiler aquí es carísimo, pero el barrio es excelente.", "text": "O aluguel aqui é caríssimo, mas o bairro é ótimo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e27b09d8-b823-5441-9832-7fc4860ae771.mp3"}]'::jsonb, '[{"title": "Al comparar dos seres, nunca «mais bom» ni «mais grande»", "body": "El español permite «más bueno/más grande», pero al comparar DOS SERES el portugués exige la forma irregular: «Este hotel é melhor», «Meu carro é maior». (Solo al contrastar dos cualidades del mismo ser cabe «mais bom do que esperto».)"}, {"title": "El superlativo lleva «de», no «em»", "body": "Con el grupo de referencia se usa «de» contraído: «a maior cidade do país», «o melhor aluno da turma». Con «em» la frase cambia de sentido (lectura de lugar)."}, {"title": "En pt-BR la igualdad prefiere «quanto»", "body": "«Tão alto como» se entiende y es correcto, pero un brasileño dirá casi siempre «tão alto quanto». Acostumbra el oído a «quanto» para sonar natural."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «Este restaurante é ___ do que o outro.»", "options": ["melhor", "mais bom", "muito bom"], "answer": "melhor", "id": "u18q1"}, {"type": "multiple_choice", "prompt": "Completa: «São Paulo é a maior cidade ___ Brasil.»", "options": ["do", "no", "em"], "answer": "do", "id": "u18q2"}, {"type": "cloze", "prompt": "Escribe el comparativo irregular de «grande» (una palabra).", "text": "Meu apartamento é ___ do que o seu.", "answer": "maior", "accepted": ["maior"], "id": "u18q3"}, {"type": "cloze", "prompt": "Completa la comparación de igualdad (una palabra).", "text": "Ela é tão inteligente ___ o irmão.", "answer": "quanto", "accepted": ["quanto", "como"], "id": "u18q4"}, {"type": "cloze", "prompt": "Escribe el superlativo absoluto de «caro» con el sufijo -íssimo (una palabra).", "text": "Esse celular é ___: custa dez mil reais.", "answer": "caríssimo", "accepted": ["caríssimo"], "id": "u18q5"}]'::jsonb)
