insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 19, 'B2', 'Presente de subjuntivo (avanzado) y conjunciones', 'Aprende qué conjunciones portuguesas exigen presente do subjuntivo (embora, caso, para que) y cuáles piden indicativo o infinitivo. El calco del español «aunque» y «a pesar de que» es el error número uno.', '[{"heading": "Conectores que SIEMPRE piden subjuntivo", "body": "Ciertas conjunciones exigen SUBJUNTIVO, aunque el hecho sea real: presente para el presente o el futuro, imperfeito cuando la frase va en pasado. No alternan con indicativo.", "bullets": ["Concesión: embora, ainda que, mesmo que + subjuntivo.", "Condición: caso, a menos que, contanto que.", "«desde que» pide subjuntivo solo si es condición.", "Temporal va en indicativo: «Desde que ele chegou, tudo mudou»."]}, {"heading": "Los que piden indicativo o infinitivo", "body": "No todo conector de concesión rige subjuntivo. Algunos son adverbios y no cambian el verbo; otros van con infinitivo, la construcción preferida del portugués cuando el sujeto es el mismo.", "bullets": ["«mesmo assim» es adverbio: indicativo (Estou cansado; mesmo assim vou).", "«apesar de» + infinitivo: apesar de estar cansado.", "«embora» + subjuntivo: embora esteja cansado.", "«ainda assim», «porém», «no entanto»: indicativo."]}, {"heading": "Con «se» nunca va presente do subjuntivo", "body": "Aquí el hispanohablante calca y falla. El portugués usa futuro do subjuntivo para lo hipotético futuro, e indicativo para lo real o habitual. El presente do subjuntivo tras «se» es agramatical.", "bullets": ["Se eu tiver tempo, eu vou (futuro do subjuntivo).", "Se ele quiser, ele liga (nunca «se ele queira»).", "Se você está cansado, descanse (indicativo, hecho real).", "Caso sí pide presente: caso eu tenha tempo."]}]'::jsonb, '[{"pt": "Embora esteja cansado, vou trabalhar.", "es": "Aunque esté cansado, voy a trabajar.", "text": "Embora esteja cansado, vou trabalhar.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/98969eac-5c30-51aa-b4c4-9d1af2600d56.mp3"}, {"pt": "Apesar de estar cansado, vou trabalhar.", "es": "A pesar de estar cansado, voy a trabajar.", "text": "Apesar de estar cansado, vou trabalhar.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/976898f1-f28a-59f9-998e-0df52807e942.mp3"}, {"pt": "Vou levar o guarda-chuva caso chova mais tarde.", "es": "Voy a llevar el paraguas por si llueve más tarde.", "text": "Vou levar o guarda-chuva caso chova mais tarde.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/08409ed0-2e74-5b41-a22a-528adf693756.mp3"}, {"pt": "Se eu tiver tempo amanhã, eu te ligo.", "es": "Si tengo tiempo mañana, te llamo.", "text": "Se eu tiver tempo amanhã, eu te ligo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/ad4ba04a-a6b9-5122-bece-081467f0c7e3.mp3"}]'::jsonb, '[{"title": "«Embora» siempre con subjuntivo, aunque el hecho sea real", "body": "En español «aunque llueve» (hecho real) es correcto con indicativo. En portugués «embora» NUNCA admite indicativo: «Embora chova muito, eu saio». Si quieres indicativo, usa otro conector: «Chove muito, mas eu saio» o «Chove muito; mesmo assim eu saio»."}, {"title": "«Apesar de» pide infinitivo, no verbo conjugado", "body": "El calco de «a pesar de que trabaja mucho» produce el incómodo «apesar de que trabalha». El portugués prefiere el infinitivo: «Apesar de trabalhar muito, ele não ganha bem». Si el sujeto es distinto, usa infinitivo personal: «apesar de eles trabalharem muito»."}, {"title": "Tras «se» no cabe el presente do subjuntivo", "body": "«Se eu tenha tempo» y «se ele queira» son agramaticales en portugués. Para lo hipotético futuro se usa el futuro do subjuntivo: «se eu tiver», «se ele quiser». El presente do subjuntivo sí aparece tras «caso», que es su equivalente: «caso eu tenha tempo»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta: «Embora ___ muito, ele nunca reclama.»", "options": ["trabalhe", "trabalha", "trabalhará"], "answer": "trabalhe", "id": "u19q1"}, {"type": "multiple_choice", "prompt": "¿Cuál es la construcción que prefiere el portugués (la estándar)?", "options": ["Apesar de estar cansado, ele saiu.", "Apesar de que estava cansado, ele saiu.", "Apesar de esteja cansado, ele saiu."], "answer": "Apesar de estar cansado, ele saiu.", "id": "u19q2"}, {"type": "multiple_choice", "prompt": "Completa con el tiempo que exige «se»: «Se você ___ o documento, me avise.»", "options": ["receber", "receba", "recebia"], "answer": "receber", "id": "u19q3"}, {"type": "cloze", "prompt": "Escribe UNA palabra: el verbo entre paréntesis en presente do subjuntivo, 3ª persona del singular.", "text": "Vou levar o guarda-chuva caso ___ (chover) à tarde.", "answer": "chova", "accepted": ["chova"], "id": "u19q4"}, {"type": "cloze", "prompt": "Escribe UNA palabra: el verbo entre paréntesis en presente do subjuntivo, 1ª persona del plural (nós).", "text": "Ele sempre explica tudo de novo para que nós ___ (entender) o problema.", "answer": "entendamos", "accepted": ["entendamos"], "id": "u19q5"}]'::jsonb)
