insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 20, 'B2', 'Futuro del subjuntivo + Imperfecto del subjuntivo', 'El portugués usa a diario un tiempo que el español moderno perdió: el futuro do subjuntivo, para lo que va a pasar. Y el imperfeito do subjuntivo, para lo hipotético.', '[{"heading": "Futuro do subjuntivo: lo que aún no pasó", "body": "Tras quando, se, enquanto, assim que, sempre que, depois que y logo que, cuando hablas de algo FUTURO o eventual, el portugués exige futuro do subjuntivo. El español pone presente ahí; por eso este tiempo suena tan raro al principio.", "bullets": ["Quando eu tiver tempo, eu te ligo.", "Se você quiser, a gente sai hoje.", "Assim que eles chegarem, começamos a reunião.", "Enquanto houver dúvida, ninguém assina."]}, {"heading": "Cómo se forma: desde la 3ª persona del plural", "body": "Toma el pretérito perfeito en eles, quita el -am final y ahí tienes la raíz: fizeram → fizer, tiveram → tiver, foram → for, puderam → puder, quiseram → quiser, disseram → disser. Para eu/você/ele la raíz va desnuda; luego -es, -mos, -em.", "bullets": ["Verbos regulares: falar → falaram → falar (igual al infinitivo).", "Irregulares: ser e ir → for; ter → tiver; fazer → fizer.", "Vir → vieram → vier; trazer → trouxeram → trouxer.", "Nunca digas quando eu terei nem quando eu tenha."]}, {"heading": "Imperfeito do subjuntivo: lo hipotético", "body": "Del mismo «eles» del pretérito, pero quitando -ram: fizeram→fizesse, tiveram→tivesse, foram→fosse. Sirve para lo irreal: compara «se eu tiver dinheiro, viajo» (posible) con «se eu tivesse dinheiro, viajaria» (fantasía).", "bullets": ["Se eu fosse você, aceitaria a proposta.", "Ela queria que nós ficássemos mais um pouco.", "Era como se ele não soubesse de nada.", "Se tivesse acordado cedo, teria pegado o voo."]}]'::jsonb, '[{"pt": "Quando eu tiver tempo, eu te ligo.", "es": "Cuando tenga tiempo, te llamo.", "text": "Quando eu tiver tempo, eu te ligo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/7bac6ae3-82a4-5661-916b-ea0a09345f80.mp3"}, {"pt": "Se você puder, me manda o relatório hoje.", "es": "Si puedes, mándame el informe hoy.", "text": "Se você puder, me manda o relatório hoje.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1bdad665-6d80-59d3-b9e2-e1c22fb806aa.mp3"}, {"pt": "Assim que eles fizerem o pagamento, a gente envia o produto.", "es": "En cuanto hagan el pago, enviamos el producto.", "text": "Assim que eles fizerem o pagamento, a gente envia o produto.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/f3084760-3a33-5556-bccd-24898b09c208.mp3"}, {"pt": "Se eu fosse você, eu não diria nada agora.", "es": "Si yo fuera tú, no diría nada ahora.", "text": "Se eu fosse você, eu não diria nada agora.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/52085ba8-da32-50cd-b833-ba762401d954.mp3"}]'::jsonb, '[{"title": "\"Quando eu tenho\" y \"quando eu tenha\": los dos calcos del español", "body": "Para algo futuro se dice quando eu tiver tempo. El presente de indicativo (quando eu tenho tempo) es correcto pero significa otra cosa: lo habitual, lo de siempre. Y quando eu tenha, calco del subjuntivo español, sencillamente no existe en portugués."}, {"title": "La trampa de los verbos regulares", "body": "En los regulares el futuro do subjuntivo coincide con el infinitivo: se você falar, quando ela comer. Eso te hace creer que basta con el infinitivo siempre. Pero en los irregulares no coincide: es se você for, quando ela tiver, assim que eles fizerem, nunca ser, ter, fazer."}, {"title": "Futuro do subjuntivo o imperfeito: depende de cuán real sea", "body": "Se eu tiver dinheiro, eu viajo habla de una posibilidad real. Se eu tivesse dinheiro, eu viajaria habla de algo que hoy no es cierto. Elegir mal cambia el mensaje: prometes un viaje o solo sueñas con él."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Elige la forma correcta para hablar del futuro: «Quando eu ___ o dinheiro, eu compro o carro.»", "options": ["tiver", "terei", "tenha"], "answer": "tiver", "id": "u20q1"}, {"type": "multiple_choice", "prompt": "¿Cuál es el futuro do subjuntivo del verbo ''ser'' (eu)?", "options": ["for", "seja", "fosse"], "answer": "for", "id": "u20q2"}, {"type": "cloze", "prompt": "Completa con el futuro do subjuntivo de ''poder'' (você).", "text": "Me avise assim que você ___.", "answer": "puder", "accepted": ["puder"], "id": "u20q3"}, {"type": "cloze", "prompt": "Completa con el futuro do subjuntivo de ''fazer'' (eles), para una condición futura.", "text": "Enviaremos o produto depois que eles ___ o pagamento.", "answer": "fizerem", "accepted": ["fizerem"], "id": "u20q4"}, {"type": "cloze", "prompt": "Completa con el imperfeito do subjuntivo de ''ser'' (eu), en una hipótesis irreal.", "text": "Se eu ___ você, eu aceitaria a proposta.", "answer": "fosse", "accepted": ["fosse"], "id": "u20q5"}]'::jsonb)
