  quiz = excluded.quiz, updated_at = now();
insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 21, 'B2', 'Período hipotético y futuro do pretérito', 'Los tres condicionales del portugués y el futuro do pretérito en «-ia». Aprendes a formar el imperfeito do subjuntivo y a no calcar el «-ría» español.', '[{"heading": "Los tres tipos de condicional", "body": "El portugués distingue tres condicionales según el grado de realidad. La forma verbal tras «se» cambia en cada uno: futuro do subjuntivo para lo probable, imperfeito do subjuntivo para lo irreal presente, y la forma compuesta para lo irreal pasado.", "bullets": ["Real: se + futuro do subjuntivo + presente o futuro.", "Irreal presente: se tivesse tempo, viajaria mais.", "Irreal pasado: se tivesse estudado, teria passado."]}, {"heading": "Cómo se forma el imperfeito do subjuntivo", "body": "Toma la tercera persona del plural del pretérito perfeito, quita «-ram» y añade «-sse». La regla funciona con todos los verbos, también con los irregulares, sin ninguna excepción.", "bullets": ["fizeram → fizesse; tiveram → tivesse; foram → fosse.", "puderam → pudesse; disseram → dissesse; quiseram → quisesse.", "El futuro do subjuntivo sale del mismo tema: fizer, tiver."]}, {"heading": "Futuro do pretérito: «-ia», nunca «-ría»", "body": "El condicional portugués termina en «-ia»: viajaria, teria, seria. En el habla brasileña se sustituye muy a menudo por el imperfeito do indicativo: «Se eu tivesse tempo, eu viajava». Ambas se oyen; en la escritura formal usa «viajaria».", "bullets": ["Escribe «viajaria»: la terminación -ia no lleva acento.", "Compuesto: teria o seria + particípio para el pasado.", "En el habla: «Se pudesse, eu ia» sustituye al condicional."]}]'::jsonb, '[{"pt": "Se eu tiver tempo amanhã, vou ligar para você.", "es": "Si tengo tiempo mañana, voy a llamarte.", "text": "Se eu tiver tempo amanhã, vou ligar para você.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/b8b303ee-ca46-5772-be77-779328e07349.mp3"}, {"pt": "Se eu tivesse mais dinheiro, viajaria pelo Brasil inteiro.", "es": "Si tuviera más dinero, viajaría por todo Brasil.", "text": "Se eu tivesse mais dinheiro, viajaria pelo Brasil inteiro.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/bdae8f48-d2fc-5975-9741-bc6d7fd4189f.mp3"}, {"pt": "Se ela tivesse estudado, teria passado no concurso.", "es": "Si ella hubiera estudiado, habría aprobado la oposición.", "text": "Se ela tivesse estudado, teria passado no concurso.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/d07820a9-ce2d-5ce2-90f8-e22f77c245e0.mp3"}, {"pt": "Se eu fosse você, eu falava com o chefe hoje.", "es": "Si yo fuera tú, hablaría con el jefe hoy (habla; en escrito: eu falaria).", "text": "Se eu fosse você, eu falava com o chefe hoje.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/0d9c9061-00f6-5a1a-9286-75061df1efe8.mp3"}]'::jsonb, '[{"title": "«viajaría» no existe en portugués", "body": "El calco del condicional español es el error más visible. En portugués la terminación es «-ia», sin tilde y sin «r» extra: viajaria, comeria, seria, teria, gostaria."}, {"title": "Tras «se» hipotético no va el presente do subjuntivo", "body": "«Se eu tenha tempo» es agramatical. Para lo probable usa el futuro do subjuntivo (se eu tiver, se ele for, se fizer); para lo irreal, el imperfeito (se eu tivesse, se ele fosse)."}, {"title": "No mezcles los tipos", "body": "«Se eu tivesse tempo, vou viajar» junta un tiempo irreal con uno real. Si la condición es «tivesse», el resultado es «viajaria» (o, en el habla, «viajava»)."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Condición probable en el futuro. Elige la forma correcta.", "options": ["falar", "falasse", "fala"], "answer": "falar", "id": "u21q1"}, {"type": "multiple_choice", "prompt": "Condición probable en el futuro: «Se eu ___ tempo amanhã, eu te ligo.»", "options": ["tiver", "tivesse", "tenho"], "answer": "tiver", "id": "u21q2"}, {"type": "cloze", "prompt": "Completa con el imperfeito do subjuntivo de «ser» (eu).", "text": "Se eu ___ você, aceitaria o convite.", "answer": "fosse", "accepted": ["fosse"], "id": "u21q3"}, {"type": "cloze", "prompt": "Completa con el futuro do pretérito (condicional) de «gostar» (eu).", "text": "Se eu pudesse, eu ___ de morar no Brasil.", "answer": "gostaria", "accepted": ["gostaria"], "id": "u21q4"}, {"type": "cloze", "prompt": "Completa con el imperfeito do subjuntivo de «ter» (eu) para formar el irreal del pasado.", "text": "Se eu ___ estudado mais, teria passado na prova.", "answer": "tivesse", "accepted": ["tivesse"], "id": "u21q5"}]'::jsonb)
