insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 22, 'B2', 'Voz pasiva y participios dobles', 'En portugués el participio de la pasiva concuerda con el sujeto, la pasiva sintética con -se también concuerda, y muchos verbos tienen dos participios: uno para ter/haver y otro para ser/estar.', '[{"heading": "Pasiva con ser: el participio concuerda", "body": "Forma: ser + participio, y el participio copia género y número del sujeto. El agente va con por, que se contrae con el artículo: por + o = pelo, por + a = pela.", "bullets": ["A ponte foi construída / As pontes foram construídas.", "O livro foi escrito / Os livros foram escritos.", "Agente: pelo professor, pela empresa, pelos alunos."]}, {"heading": "Pasiva sintética: Vendem-se casas", "body": "Con se el verbo también concuerda con el sustantivo, que es el sujeto. Si el sustantivo va en plural, el verbo va en plural. Es el error de concordancia más común de los propios brasileños.", "bullets": ["Aluga-se apartamento. / Alugam-se apartamentos.", "Vende-se uma casa. / Vendem-se casas.", "Con verbo + preposición NO concuerda: «Precisa-se de vendedores»."]}, {"heading": "Participios dobles: pago, aceito, entregue", "body": "Muchos verbos tienen dos participios. El regular acompaña a ter y haver; el irregular acompaña a ser y estar. Ambos son correctos, cada uno en su sitio.", "bullets": ["Tinha pagado a conta. / A conta foi paga.", "Tinha aceitado o convite. / O convite foi aceito.", "Também: entregado/entregue, gastado/gasto, acendido/aceso.", "Ganhar e imprimir: ganhado/ganho, imprimido/impresso."]}]'::jsonb, '[{"pt": "As casas foram vendidas pela imobiliária no mês passado.", "es": "Las casas fueron vendidas por la inmobiliaria el mes pasado.", "text": "As casas foram vendidas pela imobiliária no mês passado.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/aa5d9912-7fe7-5046-9b4b-1d8e046b1894.mp3"}, {"pt": "Alugam-se salas comerciais no centro da cidade.", "es": "Se alquilan salas comerciales en el centro de la ciudad.", "text": "Alugam-se salas comerciais no centro da cidade.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/4ebb44db-336f-5206-93ee-b172731272d1.mp3"}, {"pt": "O gerente tinha aceitado o pedido, mas o pedido não foi aceito pela diretoria.", "es": "El gerente había aceptado el pedido, pero el pedido no fue aceptado por la dirección.", "text": "O gerente tinha aceitado o pedido, mas o pedido não foi aceito pela diretoria.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/e9be4f95-068b-5912-8610-69a556774e46.mp3"}, {"pt": "Os documentos já estão entregues, embora eu tenha entregado tudo atrasado.", "es": "Los documentos ya están entregados, aunque yo entregué todo con retraso.", "text": "Os documentos já estão entregues, embora eu tenha entregado tudo atrasado.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/1c3ba3b0-4a3b-56d5-9878-308914d4083a.mp3"}]'::jsonb, '[{"title": "El participio no concuerda", "body": "El hispanohablante deja el participio en masculino singular. Si el sujeto es femenino o plural, el participio cambia: A casa foi vendida, As casas foram vendidas, no ''foi vendido''."}, {"title": "Vende-se casas", "body": "Calcado del español ''se venden casas'' pensando en singular. En portugués casas es el sujeto, así que el verbo va en plural: Vendem-se casas. Con singular: Vende-se uma casa."}, {"title": "Foi pagado, foi aceitado", "body": "No están ''prohibidos'' como palabras, pero tras ser y estar el portugués prefiere la forma irregular: foi pago, foi aceito, está entregue. Las regulares van con ter y haver: tinha pagado, tinha aceitado."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "Completa: «As pontes ___ construídas em 1950.» (pasiva con ser, sujeto plural femenino)", "options": ["foram", "foi", "era"], "answer": "foram", "id": "u22q1"}, {"type": "multiple_choice", "prompt": "¿Cuál es la forma correcta de la pasiva sintética con el sustantivo en plural?", "options": ["Alugam-se apartamentos", "Aluga-se apartamentos", "Alugado-se apartamentos"], "answer": "Alugam-se apartamentos", "id": "u22q2"}, {"type": "multiple_choice", "prompt": "Según la regla clásica que acabas de ver (participio REGULAR con ter/haver), ¿qué frase la aplica?", "options": ["O cliente tinha pagado a conta", "O cliente tinha pagada a conta", "O cliente tinha pagas a conta"], "answer": "O cliente tinha pagado a conta", "id": "u22q3"}, {"type": "cloze", "prompt": "Completa con el participio de ''pagar'' que se usa tras ''ser''. Fíjate en el género de ''a conta''.", "text": "A conta já foi ___ pelo cliente.", "answer": "paga", "accepted": ["paga"], "id": "u22q4"}, {"type": "cloze", "prompt": "Completa con el participio de ''escrever''. Concuerda con ''as cartas''.", "text": "As cartas foram ___ pela secretária.", "answer": "escritas", "accepted": ["escritas"], "id": "u22q5"}]'::jsonb)
