insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 23, 'B2', 'Discurso indirecto y colocación pronominal', 'Aprende a reportar lo que alguien dijo retrocediendo los tiempos verbales y a colocar el pronombre como lo hace un brasileño: próclise en el habla, ênclise en la norma formal escrita.', '[{"heading": "Reportar en pasado: los tiempos retroceden", "body": "Cuando el verbo que reporta está en pasado, lo dicho suele retroceder un paso: el presente pasa a imperfeito, el pretérito perfeito pasa a mais-que-perfeito y el futuro se vuelve «ia» + infinitivo. Si lo dicho sigue vigente, también puedes mantener el presente.", "bullets": ["«Eu trabalho» → «Ele disse que trabalhava».", "«Eu fiz» → «Ele disse que tinha feito».", "«Vou viajar» → «Ele disse que ia viajar».", "Sigue vigente: «Ele disse que mora aqui» también vale."]}, {"heading": "Próclise o ênclise: es registro, no error", "body": "El brasileño habla con próclise: el pronombre va antes del verbo («me disse», «te ligo»), incluso al empezar la frase. La norma formal escrita prefiere la ênclise en esa posición inicial («Disse-me ontem»). Las dos formas existen: cambia el registro, no la corrección.", "bullets": ["Habla y textos informales: «Me disse ontem», «Te ligo depois».", "Norma formal escrita: «Disse-me ontem», «Ligo-lhe depois».", "Imperativo reportado: «pediu para eu ir» o «pediu que eu fosse»."]}, {"heading": "Palabras que atraen el pronombre", "body": "Las negaciones, algunos adverbios y las palabras interrogativas atraen el pronombre hacia delante. Ahí la próclise es obligatoria también en la norma formal: con «não», «nunca», «ninguém», «já», «quem» o «que», el pronombre no queda pegado detrás del verbo.", "bullets": ["Negación: «Não me disse nada», nunca «Não disse-me nada».", "Adverbio: «Nunca te vi tão feliz».", "Interrogativa: «Quem te falou isso?», «Ninguém me avisou»."]}]'::jsonb, '[{"pt": "Ele disse que trabalhava em São Paulo.", "es": "Dijo que trabajaba en São Paulo.", "text": "Ele disse que trabalhava em São Paulo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/106dce98-a2b0-5b19-9125-c941f1893c01.mp3"}, {"pt": "Ela disse que já tinha entregado o projeto.", "es": "Dijo que ya había entregado el proyecto.", "text": "Ela disse que já tinha entregado o projeto.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/a0a5bee5-1972-56ef-a8fa-50fd38421555.mp3"}, {"pt": "O chefe pediu para eu chegar mais cedo.", "es": "El jefe me pidió que llegara más temprano.", "text": "O chefe pediu para eu chegar mais cedo.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/97f5f230-5d71-59ce-9f52-60418d66cd3e.mp3"}, {"pt": "Ninguém te falou isso? Ele me disse ontem.", "es": "¿Nadie te dijo eso? Él me lo dijo ayer.", "text": "Ninguém te falou isso? Ele me disse ontem.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/9e1447db-c029-57c5-988d-cd0f64c5f94f.mp3"}]'::jsonb, '[{"title": "Usar ênclise donde el brasileño usa próclise", "body": "Tras aprender la regla formal, muchos dicen «Disse-me ontem» en una conversación. No está mal, pero suena a documento. Hablando, un brasileño dice «Me disse ontem». Elige según el registro: habla y chat = próclise; texto formal = ênclise."}, {"title": "Olvidar «pediu para eu ir»", "body": "El hispanohablante traduce el imperativo reportado siempre con «que» + subjuntivo. «Pediu que eu fosse» es correcto y formal, pero en Brasil se oye más «Pediu para eu ir». Ojo: es «para EU ir», nunca «para mim ir»."}, {"title": "Colocar el pronombre detrás con negación", "body": "«Não disse-me nada» es un error real, incluso en el registro más formal. La negación atrae el pronombre: «Não me disse nada». Lo mismo con «nunca», «ninguém», «já», «quem» y «que»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "«Eu fiz o relatório», disse ele. ¿Cómo se reporta esa frase en pasado?", "options": ["Disse que tinha feito o relatório.", "Disse que fazia o relatório.", "Disse que faria o relatório."], "answer": "Disse que tinha feito o relatório.", "id": "u23q1"}, {"type": "multiple_choice", "prompt": "En un e-mail formal, ¿cómo empezarías la frase «Me dijo que llegaría tarde»?", "options": ["Disse-me que chegaria tarde.", "Disse que me chegaria tarde.", "Disse que chegaria-me tarde."], "answer": "Disse-me que chegaria tarde.", "id": "u23q2"}, {"type": "cloze", "prompt": "«Estou cansada», disse ela ontem. Reporta la frase en pasado (hoy ella ya descansó).", "text": "Ela disse que ___ cansada.", "answer": "estava", "accepted": ["estava"], "id": "u23q3"}, {"type": "cloze", "prompt": "Completa con el auxiliar del mais-que-perfeito composto (él ya las había comprado antes).", "text": "Ele disse que já ___ comprado as passagens.", "answer": "tinha", "accepted": ["tinha", "havia"], "id": "u23q4"}, {"type": "cloze", "prompt": "Completa con el pronombre de primera persona: «Nadie me avisó de la reunión».", "text": "Ninguém ___ avisou da reunião.", "answer": "me", "accepted": ["me"], "id": "u23q5"}]'::jsonb)
