insert into public.study_theory (course_id, unit_order, cefr_level, title, summary, sections, examples, pitfalls, quiz)
values ('20000000-0000-0000-0000-000000000002', 24, 'B2', 'Conectores B2, subordinadas y régimen verbal', 'Cierras el B2 con los conectores que exigen subjuntivo (embora, caso, para que) frente a los de indicativo, y con la regência: la preposición que cada verbo pide en portugués.', '[{"heading": "Conector que pide subjuntivo vs. indicativo", "body": "Concesión, condición y finalidad piden subjuntivo: embora, nem que, caso, a menos que, para que. Causa y consecuencia van con indicativo: porque, já que, uma vez que, visto que, portanto. El español «aunque» admite ambos; «embora» NO: siempre subjuntivo.", "bullets": ["Embora, caso, a menos que, para que, nem que: subjuntivo.", "Porque, já que, uma vez que, visto que: indicativo.", "«Embora ele está cansado» no existe: «embora ele esteja cansado».", "Caso + presente do subjuntivo: «caso você queira»."]}, {"heading": "Regência: la preposición que exige el verbo", "body": "Varios verbos piden preposición donde el español no la usa, o piden otra distinta. Aprende el verbo con su preposición pegada, como una sola pieza.", "bullets": ["Assistir a um filme; obedecer a alguém.", "Gostar de, precisar de, lembrar-se de, esquecer-se de.", "Ir a um lugar; chegar a / em um lugar.", "Con artículo femenino se contrae: obedecer à professora."]}, {"heading": "Conectores de registro escrito", "body": "En textos formales el contraste y la consecuencia se marcan con conectores propios, normalmente entre comas o tras punto. Todos van con indicativo: organizan ideas, no crean subordinada de subjuntivo.", "bullets": ["Contraste: no entanto, contudo, entretanto.", "Consecuencia: portanto, logo, por conseguinte.", "Adición: além disso; reformulación: ou seja."]}]'::jsonb, '[{"pt": "Assisti ao filme ontem à noite e gostei muito dele.", "es": "Vi la película anoche y me gustó mucho.", "text": "Assisti ao filme ontem à noite e gostei muito dele.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/54c124b9-479c-5c62-bc30-6d0ec9d5ae72.mp3"}, {"pt": "Embora esteja cansado, vou terminar o relatório hoje.", "es": "Aunque esté cansado, voy a terminar el informe hoy.", "text": "Embora esteja cansado, vou terminar o relatório hoje.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/80c6edf1-d61b-5125-b201-6595716375c9.mp3"}, {"pt": "Preciso de mais tempo; no entanto, o prazo não muda.", "es": "Necesito más tiempo; sin embargo, el plazo no cambia.", "text": "Preciso de mais tempo; no entanto, o prazo não muda.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/3ef26fdb-cde0-5e81-b2c1-44352635734c.mp3"}, {"pt": "Quando cheguei em casa, lembrei-me do documento esquecido.", "es": "Cuando llegué a casa, me acordé del documento olvidado.", "text": "Quando cheguei em casa, lembrei-me do documento esquecido.", "audio_url": "https://wiauinufpbkmjlbqlkxo.supabase.co/storage/v1/object/public/audio/study/32aa2593-528e-52f9-8f08-209bc0e0a96c.mp3"}]'::jsonb, '[{"title": "«Assisti o filme» / «obedecer o pai»: falta la preposición", "body": "El español dice «ver la película» y «obedecer al padre» sin la misma preposición. La norma culta brasileña pide assistir A y obedecer A: «Assisti ao filme», «Ele obedece aos pais». En la conversación diaria muchos brasileños dicen «assisti o filme»; se entiende, pero en la escritura y en un examen se corrige."}, {"title": "«Embora» nunca lleva indicativo", "body": "Como el español «aunque» acepta indicativo («aunque está cansado»), el hispanohablante calca: «embora está cansado». En portugués es agramatical. Embora, nem que, caso, a menos que y para que exigen subjuntivo siempre: «embora esteja», «caso venha», «para que possamos»."}, {"title": "«Chegar a» y «chegar em»: las dos existen", "body": "La norma clásica escribe «cheguei a casa», pero en Brasil «cheguei em casa» es lo normal y hoy se acepta como uso brasileño corriente, incluso escrito. Lo que sí falla es olvidar la preposición: «cheguei casa». Con ir, la norma mantiene «ir a»: «vou ao mercado»."}]'::jsonb, '[{"type": "multiple_choice", "prompt": "¿Qué frase respeta la norma culta del portugués?", "options": ["Ontem assisti ao jogo com meus amigos.", "Ontem assisti o jogo com meus amigos.", "Ontem assisti no jogo com meus amigos."], "answer": "Ontem assisti ao jogo com meus amigos.", "id": "u24q1"}, {"type": "multiple_choice", "prompt": "El conector «embora» exige subjuntivo. Elige la forma correcta.", "options": ["Embora chova muito, vamos sair.", "Embora chove muito, vamos sair.", "Embora choveu muito, vamos sair."], "answer": "Embora chova muito, vamos sair.", "id": "u24q2"}, {"type": "cloze", "prompt": "Completa con la preposición que exige el verbo «precisar».", "text": "Eu preciso ___ mais tempo para terminar o projeto.", "answer": "de", "accepted": ["de"], "id": "u24q3"}, {"type": "cloze", "prompt": "Completa con la preposición que exige el verbo «obedecer».", "text": "As crianças obedecem ___ professora sem reclamar.", "answer": "à", "accepted": ["a"], "id": "u24q4"}, {"type": "multiple_choice", "prompt": "Elige el conector de contraste propio del registro escrito.", "options": ["O prazo acabou; no entanto, continuamos trabalhando.", "O prazo acabou; portanto, continuamos trabalhando.", "O prazo acabou; além disso, continuamos trabalhando."], "answer": "O prazo acabou; no entanto, continuamos trabalhando.", "id": "u24q5"}]'::jsonb)
